mapper.select:
/* AdminPotholeMapper.selectImsPotholeList - 현장관리 목록 조회 */
SELECT s.site_name AS siteName , p.report_no AS reportNo , DATE_FORMAT(p.report_date, '%y-%m-%d %H:%i') AS reportDate , p.status_cd AS statusCd , cc.cd_code_nm AS statusNm , p.process_note AS workContent , p.direction_cd AS directionCd , p.pavement_type_cds AS pavementTypeCds , p.occur_place_cds AS occurPlaceCds , p.addr , p.sta_text AS staText , DATE_FORMAT(p.work_start_at, '%y-%m-%d %H:%i') AS workStartAt , DATE_FORMAT(p.work_end_at, '%y-%m-%d %H:%i') AS workEndAt , p.receipt_gb_cd AS receiptGbCd , c.CD_CODE_NM AS receiptGbNm FROM pothole p LEFT JOIN site_info s ON s.site_cd = p.site_cd AND s.del_yn = 'N' LEFT JOIN cd_common cc ON cc.cd_div = '005' AND cc.use_yn = 'Y' AND cc.cd_code = p.status_cd LEFT JOIN cd_common c ON p.receipt_gb_cd = c.CD_CODE and c.CD_DIV = '006' and c.USE_YN = 'Y' WHERE 1=1 AND p.del_yn = 'N'
ORDER BY p.report_date DESC
LIMIT #{offset}, #{pageSize}

mapper.update:
/* AdminPotholeMapper.updatePotholeStatusBulk - 포트홀 상태 일괄 변경 */
UPDATE pothole
SET
    status_cd = #{statusCd},
    update_datetime = NOW()

        , update_ip = #{updateIp}

WHERE report_no IN

    #{rn}

mapper.delete:
/* AdminPotholeMapper.deleteWorkEquipmentByReportNo - 작업 장비 삭제 */
DELETE FROM pothole_work_equipment
WHERE report_no = #{reportNo}

/* AdminPotholeMapper.deleteWorkPersonnelByReportNo - 작업 인력 삭제 */
DELETE FROM pothole_work_personnel
WHERE report_no = #{reportNo}

/* AdminPotholeMapper.deleteWorkMaterialByReportNo - 작업 자재 삭제 */
DELETE FROM pothole_work_material
WHERE report_no = #{reportNo}

/* AdminPotholeMapper.deleteWorkScopeByReportNo - 작업 범위 삭제 */
DELETE FROM pothole_work_scope
WHERE report_no = #{reportNo}

mapper.select:
/* ImsMapper.getImsStatusSummary - 상태별 건수 집계 */
SELECT
IFNULL(SUM(CASE WHEN p.status_cd = 'RECEIVED' THEN 1 ELSE 0 END), 0) AS received_cnt,
IFNULL(SUM(CASE WHEN p.status_cd = 'WORKING'  THEN 1 ELSE 0 END), 0) AS working_cnt,
IFNULL(SUM(CASE WHEN p.status_cd IN ('DONE') THEN 1 ELSE 0 END), 0) AS done_cnt,
IFNULL(SUM(CASE WHEN p.status_cd = 'HOLD'     THEN 1 ELSE 0 END), 0) AS hold_cnt,
COUNT(*) AS total_cnt
FROM pothole p

    AND p.del_yn = 'N'


        AND p.site_cd IN

            #{sc}





        AND p.site_cd = #{siteCd}




        AND p.report_date >= #{strtDt}


        AND p.report_date <= #{endDt}

SELECT p.report_no AS reportNo, DATE_FORMAT(p.report_date, '%Y') AS reportYear, DATE_FORMAT(p.report_date, '%m') AS reportMonth, s.site_name AS siteName, p.addr AS region, CASE WHEN p.direction_cd = 'UP' THEN '상행' WHEN p.direction_cd = 'DOWN' THEN '하행' ELSE '' END AS directionNm, p.addr AS locationInfo, p.process_note AS detailInfo, DATE_FORMAT(p.report_date, '%Y.%m.%d') AS reportDate, DATE_FORMAT(p.report_date, '%m/%d') AS reportDateMmdd, DATE_FORMAT(p.report_date, '%Y.%m.%d') AS workDate, DATE_FORMAT(p.report_date, '%m/%d') AS workDateMmdd, DATE_FORMAT(p.report_date, '%H:%i') AS reportTime, cw.cd_code_nm AS weatherNm, DATE_FORMAT(p.report_date, '%H:%i') AS workTime, cww.cd_code_nm AS workWeatherNm, '' AS pavementTypeCds, '' AS occurPlaceCds, p.lane_info AS laneInfo, p.report_remark AS reportRemark, p.work_qty AS workQty, p.convert_work_qty AS convertWorkQty, p.account_work_qty AS accountWorkQty, NULL AS widthM, NULL AS heightM, NULL AS areaM2, NULL AS depthCm, NULL AS spanM, bf.img_path AS beforeImgPath, bf.img_name AS beforeImgName, af.img_path AS afterImgPath, af.img_name AS afterImgName FROM pothole p LEFT JOIN site_info s ON s.site_cd = p.site_cd LEFT JOIN cd_common cw ON cw.cd_div = '007' AND cw.cd_code = p.weather_cd LEFT JOIN cd_common cww ON cww.cd_div = '007' AND cww.cd_code = p.work_weather_cd LEFT JOIN ( SELECT p1.report_no, p1.file_path AS img_path, p1.file_name AS img_name FROM pothole_photo p1 INNER JOIN ( SELECT report_no, COALESCE(MIN(CASE WHEN is_main = 'Y' THEN sort_no END), MIN(sort_no)) AS pick_sort_ord FROM pothole_photo WHERE photo_gb = 'BEFORE' GROUP BY report_no ) x ON p1.report_no = x.report_no AND p1.sort_no = x.pick_sort_ord WHERE p1.photo_gb = 'BEFORE' ) bf ON bf.report_no = p.report_no LEFT JOIN ( SELECT p1.report_no, p1.file_path AS img_path, p1.file_name AS img_name FROM pothole_photo p1 INNER JOIN ( SELECT report_no, COALESCE(MIN(CASE WHEN is_main = 'Y' THEN sort_no END), MIN(sort_no)) AS pick_sort_ord FROM pothole_photo WHERE photo_gb = 'AFTER' GROUP BY report_no ) x ON p1.report_no = x.report_no AND p1.sort_no = x.pick_sort_ord WHERE p1.photo_gb = 'AFTER' ) af ON af.report_no = p.report_no WHERE p.report_no IN
#{reportNo}
ORDER BY DATE_FORMAT(p.report_date, '%m') ASC, p.report_date ASC, p.report_no ASC
